scwin.ODR_KND_CD_IMP_CVSSL_CNTR_ODR = "C1";
scwin.ODR_KND_CD_TS_ODR = "CT";
scwin.ODR_KND_CD_IMP_GNRL_CNTR_ODR = "C2";
scwin.ODR_KND_CD_EXP_GNRL_CNTR_ODR = "C4";
scwin.ODR_KND_CD_OFF_HIRE_ODR = "C6";
scwin.ODR_KND_CD_EMPTY_POSITION_ODR = "C7";
scwin.SELF_CLS_CD_SELF_CRRYOUT = "JE";
scwin.CRRYINOUT_CLS_CD_OUT = "O";
scwin.IMP_EXP_CLS_CD_IMP = "I";
scwin.WRK_PL_CLS_CD_DOOR = "D";
scwin.WRK_STP_CD_SHUTTLE = "0001";
scwin.WRK_STP_CD_TRANS = "0002";
scwin.INDVDL_ALLOCCAR_TEMPORARY = "1";
scwin.CNTR_TYP_CD_RF = "RF";
scwin.CNTR_STS_CD_REPAIR = "R";
scwin.CMPSTCRG_KND_CD_DD = "DD";
scwin.GATE_INOUT_CLS_CD_OUT = "O";

scwin.count = 0;

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.wrkPlCd = (scwin.params && scwin.params.wrkPlCd) ? scwin.params.wrkPlCd : "";
    scwin.odrNo = (scwin.params && scwin.params.odrNo) ? scwin.params.odrNo : "";
    scwin.cntrNo = (scwin.params && scwin.params.cntrNo) ? scwin.params.cntrNo : "";
    scwin.loginId = $c.ses.getUserId();
    scwin.sysAdminYn = $c.ses.getSysAdminYn ? $c.ses.getSysAdminYn() : "0";
    scwin.sysdate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    let currDate = new Date();
    scwin.sysDtm = scwin.sysdate + scwin.leadingZeros(currDate.getHours(), 2) + scwin.leadingZeros(currDate.getMinutes(), 2);
};

scwin.onUdcCompleted = async function() {
    if (scwin.wrkPlCd != "") {
        ed_wrkPlCd.setValue(scwin.wrkPlCd);
        txt_odrNo.setValue(scwin.odrNo);
        txt_cntrNo.setValue(scwin.cntrNo);
        await scwin.f_Retrieve("0");
    }
    ed_wrkPlCd.setFocus();
};

scwin.leadingZeros = function(n, digits) {
    let zero = "";
    n = n.toString();
    if (n.length < digits) {
        for (let i = 0; i < digits - n.length; i++) {
            zero += "0";
        }
    }
    return zero + n;
};

scwin.btn_Init_onclick = function(e) {
    scwin.f_batch();
};

scwin.f_batch = async function() {
    let allowedUsers = ["hurrah", "cmh0313", "areum", "cukie01", "zampion", "newsdw", "origin", "281776"];
    if (allowedUsers.indexOf(scwin.loginId) >= 0 && ed_wrkPlCd.getValue() == "6C01") {
        await scwin.pectbatch();
        if (allowedUsers.indexOf(scwin.loginId) >= 0 && ed_lineCd.getValue() == "SITC") {
            await scwin.sitcbatch();
        }
        if (allowedUsers.indexOf(scwin.loginId) >= 0 && ed_lineCd.getValue() == "HSD") {
            await scwin.mailbatch();
        }
    }
};

scwin.f_batch2 = async function() {
    await scwin.pectbatch();
    await scwin.sitcbatch();
};

scwin.btn_Retrieve_onclick = function(e) {
    scwin.f_Retrieve("1");
};

scwin.f_Retrieve = async function(p_gubun) {
    scwin.badChassisNo = false;
    let chk = await $c.gus.cfValidate([ed_wrkPlCd]);
    if (!chk) {
        return;
    }
    if (p_gubun == "1") {
        if (txt_vehclNo.getValue() == "" && txt_cntrNo.getValue() == "" && txt_odrNo.getValue() == "") {
            let confirmResult = await $c.win.confirm("조회 조건이 작업장 뿐일 경우는 오랜 시간이 소요됩니다. 그래도 검색하시겠습니까?");
            if (!confirmResult) {
                return;
            }
        }
    }

    let odrKndQry = scwin.ODR_KND_CD_IMP_CVSSL_CNTR_ODR + "','" + scwin.ODR_KND_CD_TS_ODR;
    let odrKndQryVal = "";
    if (txt_odrKndQry.getValue() != "") {
        odrKndQryVal = odrKndQry;
    }

    let cntrSpecVal = lc_cntrSpec.getValue();
    let crryinoutYnVal = lc_crryinoutYn.getValue();

    // TODO: ds_Grid1.DataId 방식 → submission 또는 별도 조회 방식으로 전환 필요
    // 원본은 ds_Grid1.DataId = URL + params; ds_Grid1.Reset(); 패턴
    // WebSquare에서는 submission ref에 검색조건을 담아 호출하는 방식으로 변환 필요
    // 현재는 직접 URL 호출 방식을 유지하되 TODO 표시
    let url = "/ds.op.wrkrslts.cywrkrslts.RetrieveGateinIntendInformationCMD.do"
        + "?wrkPlCd=" + ed_wrkPlCd.getValue()
        + "&lineCd=" + ed_lineCd.getValue()
        + "&cntrNo=" + txt_cntrNo.getValue()
        + "&cntrNo2=" + txt_cntrNo2.getValue()
        + "&vehclNo=" + txt_vehclNo.getValue()
        + "&odrNo=" + txt_odrNo.getValue()
        + "&dptArvWrkPlCd=" + ed_dptArvWrkPlCd.getValue()
        + "&cntrSpec=" + cntrSpecVal
        + "&vsslCd=" + ed_vsslCd.getValue()
        + "&portCnt=" + txt_portCnt.getValue()
        + "&crryinoutYn=" + crryinoutYnVal
        + "&odrKndQry=" + odrKndQryVal
        + "&gateInslYn=" + scwin.GATE_INSL_YN
        + "&hveqAtmtYn=" + scwin.HVEQ_ATMT_YN
        + "&gateAtmtYn=" + scwin.GATE_ATMT_YN
        + "&preInfoSndYn=" + scwin.PRE_INFO_SND_YN
        + "&gateinoutCls=O";
    // TODO: DataId+Reset 패턴을 submission으로 전환
    ds_Grid1.setJSON(url);
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true)
        scwin.f_openPopUp(disGubun, pVal, "", "T", "T");
    else
        scwin.f_openPopUp(disGubun, "", pVal, "T", "T");
};

scwin.f_openPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = null;

    if (disGubun == "1") {
        if (selfCar.getValue() != "") return;
        rtnList = $c.gus.cfCommonPopUp("retrieveVehiclesNo", pCode, pName, pClose, null, null, null, null, null, "400", null, null, null, null, pAllSearch, "차량번호,차량단축코드,차량번호");
        $c.gus.cfSetReturnValue(rtnList, txt_vehclShortCd, txt_vehclNo, null);
    } else if (disGubun == "2") {
        rtnList = $c.gus.cfCommonPopUp("retrieveWrkPlInfo", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "출도착지,작업장코드,작업장명");
        $c.gus.cfSetReturnValue(rtnList, ed_dptArvWrkPlCd, txt_dptArvWrkPlNm, null);
    } else if (disGubun == "3") {
        rtnList = $c.gus.cfCommonPopUp("retrieveLineInfo", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
        $c.gus.cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm, null);
    } else if (disGubun == "4") {
        rtnList = $c.gus.cfCommonPopUp("retrieveOrdVsslInfo", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, "T", null);
        $c.gus.cfSetReturnValue(rtnList, ed_vsslCd, txt_vsslNm, null);
    } else if (disGubun == "5") {
        scwin.f_vehclSearch("T");
    } else if (disGubun == "6") {
        rtnList = $c.gus.cfCommonPopUp("retriveGateWrkPlCd", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "작업장,작업장코드,작업장명");
        $c.gus.cfSetReturnValue(rtnList, ed_wrkPlCd, txt_wrkPlNm, null);
        if (rtnList == null) {
            scwin.LOBRAN_CD = "";
            scwin.GATE_INSL_YN = "";
            scwin.HVEQ_ATMT_YN = "";
            scwin.GATE_ATMT_YN = "";
            scwin.PRE_INFO_SND_YN = "";
        } else {
            scwin.LOBRAN_CD = rtnList[2];
            scwin.GATE_INSL_YN = rtnList[4];
            scwin.HVEQ_ATMT_YN = rtnList[5];
            scwin.GATE_ATMT_YN = rtnList[6];
            scwin.PRE_INFO_SND_YN = rtnList[7];
        }
    } else if (disGubun == "7") {
        scwin.f_eqCdSearch("T");
    }
};

scwin.f_eqCdSearch = async function(bCloseFlag) {
    bCloseFlag = (bCloseFlag == null) ? "T" : bCloseFlag;
    let lobranCd = scwin.LOBRAN_CD;
    let nowDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    let v_vehclShortCd = txt_eqCd.getValue();

    if (lobranCd == null || lobranCd == "") {
        await $c.gus.cfAlertMsg("작업장을 먼저 선택해주세요.");
        return;
    } else if (v_vehclShortCd == null || v_vehclShortCd == "") {
        await $c.gus.cfAlertMsg("차량단축번호 입력해주세요.");
        return;
    }

    let arrParam = [];
    arrParam[0] = [lobranCd, "", "", "C", nowDate, v_vehclShortCd, "", "", "GATEINOUT", "TR"];
    arrParam[1] = ["", bCloseFlag];

    let pURL = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p3.xml";
    let rtnList = await $c.win.openPopup(pURL, {
        width: 820, height: 530, modal: true,
        data: { paramTitle: "가용차량조회", arrParam: arrParam }
    });

    if (rtnList == null || (rtnList[0][0] == null && rtnList[0] == "N/A")) {
        txt_eqCd.setValue("");
        txt_eqNo.setValue("");
        return;
    }

    let firstList = rtnList[0];

    if (firstList[12] != "TR") {
        await $c.gus.cfAlertMsg("컨테이너는 트렉터만 배차 가능합니다. \n\n트렉터 차량을 선택하세요.");
        txt_eqCd.setValue("");
        txt_eqNo.setValue("");
        return;
    }
    scwin.hid_eqCd = firstList[0];
    txt_eqNo.setValue(firstList[1]);
    txt_eqCd.setValue(firstList[2]);
    scwin.hid_bondTransStDt = firstList[3];
    scwin.hid_bondTransEndDt = firstList[4];
    scwin.hid_drvEmpNo = firstList[5];
    scwin.hid_drvNm = firstList[6];
    scwin.hid_drvTelNo = firstList[7];
    scwin.hid_trsNo = firstList[8];
    scwin.hid_vehclIdCardNo = firstList[9];
    scwin.hid_chassisEqCd = firstList[10];
    scwin.hid_chassisNo = firstList[11];
    scwin.hid_vehclKndCd = firstList[12];
    scwin.hid_vehclNrmCd = firstList[13];
    scwin.hid_selfSpotClsCd = firstList[14];
    scwin.hid_copCoClntNo = firstList[15];
    scwin.hid_posnClsCd = firstList[16];

    return false;
};

scwin.f_vehclSearch = async function(bCloseFlag) {
    scwin.pre_RowPosition = ds_Grid1.getRowPosition();
    bCloseFlag = (bCloseFlag == null) ? "T" : bCloseFlag;
    let lobranCd = scwin.LOBRAN_CD;
    let v_vehclShortCd = ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "vehclNo");
    if (v_vehclShortCd.length >= 4) v_vehclShortCd = v_vehclShortCd.substring(v_vehclShortCd.length - 4, v_vehclShortCd.length);
    let nowDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    let arrParam = [];
    arrParam[0] = [lobranCd, "", "", "C", nowDate, v_vehclShortCd, "", "", "GATEINOUT", "TR"];
    arrParam[1] = ["", bCloseFlag];

    let pURL = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p3.xml";
    let rtnList = await $c.win.openPopup(pURL, {
        width: 820, height: 530, modal: true,
        data: { paramTitle: "가용차량조회", arrParam: arrParam }
    });

    if (rtnList == null || (rtnList[0][0] == null && rtnList[0] == "N/A")) {
        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "vehclNo", "");
        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "vehclShortNo", "");
        return;
    }

    let firstList = rtnList[0];

    if (firstList[12] != "TR") {
        await $c.gus.cfAlertMsg("컨테이너는 트렉터만 배차 가능합니다. \n\n트렉터 차량을 선택하세요.");
        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "vehclNo", "");
        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "vehclShortNo", "");
        return;
    }

    let row = ds_Grid1.getRowPosition();
    ds_Grid1.setCellData(row, "eqCd", firstList[0]);
    ds_Grid1.setCellData(row, "vehclNo", firstList[1]);
    ds_Grid1.setCellData(row, "vehclShortNo", firstList[2]);
    ds_Grid1.setCellData(row, "bondTransStDt", firstList[3]);
    ds_Grid1.setCellData(row, "bondTransEndDt", firstList[4]);
    ds_Grid1.setCellData(row, "drvEmpNo", firstList[5]);
    ds_Grid1.setCellData(row, "drvNm", firstList[6]);
    ds_Grid1.setCellData(row, "drvTelNo", firstList[7]);
    ds_Grid1.setCellData(row, "trsNo", firstList[8]);
    ds_Grid1.setCellData(row, "vehclIdCardNo", firstList[9]);
    ds_Grid1.setCellData(row, "chassisEqCd", firstList[10]);
    ds_Grid1.setCellData(row, "chassisNo", firstList[11]);
    ds_Grid1.setCellData(row, "vehclKndCd", firstList[12]);
    ds_Grid1.setCellData(row, "vehclNrmCd", firstList[13]);
    ds_Grid1.setCellData(row, "selfSpotClsCd", firstList[14]);
    ds_Grid1.setCellData(row, "copCoClntNo", firstList[15]);
    scwin.hid_posnClsCd = firstList[16];

    return false;
};

scwin.btn_allApp_onclick = function(e) {
    scwin.f_allApply();
};

scwin.f_allApply = async function() {
    let v_eqNo = txt_eqNo.getValue().trim();
    if (v_eqNo == null || v_eqNo == "") {
        await $c.gus.cfAlertMsg("차량번호를 조회하여 주십시오.");
        return;
    }

    if (ds_Grid1.getRowCount() > 0) {
        if (!$c.gus.cfIsNull(ed_gateOutDth.getValue())) {
            let chk = await $c.gus.cfValidate([ed_gateOutDth]);
            if (!chk) {
                return;
            }
            if (!$c.gus.cfValidateValue(ed_gateOutDth.getValue().substr(0, 8), "date=YYYYMMDD")) {
                await $c.gus.cfAlertMsg("날짜를 확인하여 주십시오.");
                ed_gateOutDth.setFocus();
                return;
            }
            if (!$c.gus.cf_gidHourCheck(ed_gateOutDth.getValue().substr(8, 4))) {
                await $c.gus.cfAlertMsg("시분을 확인하십시오.");
                ed_gateOutDth.setFocus();
                return;
            }
        }

        let confirmResult = await $c.win.confirm("차량번호를 일괄변경 하시겠습니까?");
        if (confirmResult) {
            for (let j = 0; j < ds_Grid1.getRowCount(); j++) {
                ds_Grid1.setCellData(j, "eqCd", scwin.hid_eqCd);
                ds_Grid1.setCellData(j, "vehclNo", v_eqNo);
                ds_Grid1.setCellData(j, "vehclShortNo", txt_eqCd.getValue());
                ds_Grid1.setCellData(j, "bondTransStDt", scwin.hid_bondTransStDt);
                ds_Grid1.setCellData(j, "bondTransEndDt", scwin.hid_bondTransEndDt);
                ds_Grid1.setCellData(j, "drvEmpNo", scwin.hid_drvEmpNo);
                ds_Grid1.setCellData(j, "drvNm", scwin.hid_drvNm);
                ds_Grid1.setCellData(j, "drvTelNo", scwin.hid_drvTelNo);
                ds_Grid1.setCellData(j, "trsNo", scwin.hid_trsNo);
                ds_Grid1.setCellData(j, "vehclIdCardNo", scwin.hid_vehclIdCardNo);
                ds_Grid1.setCellData(j, "chassisEqCd", scwin.hid_chassisEqCd);
                ds_Grid1.setCellData(j, "chassisNo", scwin.hid_chassisNo);
                ds_Grid1.setCellData(j, "vehclKndCd", scwin.hid_vehclKndCd);
                ds_Grid1.setCellData(j, "vehclNrmCd", scwin.hid_vehclNrmCd);
                ds_Grid1.setCellData(j, "selfSpotClsCd", scwin.hid_selfSpotClsCd);
                ds_Grid1.setCellData(j, "copCoClntNo", scwin.hid_copCoClntNo);
                ds_Grid1.setCellData(j, "gateoutDth", ed_gateOutDth.getValue());
            }
            gr_Grid1.refresh();
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["데이터", "조회"]);
        return;
    }
};

scwin.f_chassisSearch = function(bCloseFlag) {
    bCloseFlag = (bCloseFlag == null) ? "T" : bCloseFlag;
    let pClose = bCloseFlag;
    let pCode = ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "chassisNo");
    if (pCode.length >= 4) pCode = pCode.substring(pCode.length - 4, pCode.length);
    let pName = "";

    let rtnList = $c.gus.cfCommonPopUp("retrieveChassis2", pCode, pName, pClose, null, null, null, null, "TL", null, null, null, null, null, "T", null, null);
    if (!$c.gus.cfIsNull(rtnList)) {
        if (rtnList[0] != "N/A") {
            if ((scwin.hid_posnClsCd == "W" || scwin.hid_posnClsCd == "J") && rtnList[9] != "J") {
                alert("당사소유차량(트랙터)에 대해서 당사 소유의 트레일러만 입력 가능 합니다.");
                ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisNo", "");
                return false;
            } else if ((scwin.hid_posnClsCd == "W" || scwin.hid_posnClsCd == "J") && rtnList[9] == "J" && rtnList[1] == "협력11샤1111") {
                alert("당사소유차량(트랙터)에 대해서 협력11샤1111  입력 불가능 합니다.");
                ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisNo", "");
                return false;
            }

            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisNo", rtnList[1]);
            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisEqCd", rtnList[4]);

            ds_ChassisNoChangeInfo.removeAll();
            ds_ChassisNoChangeInfo.insertRow();
            ds_ChassisNoChangeInfo.setCellData(0, "eqCd", ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "eqCd"));
            ds_ChassisNoChangeInfo.setCellData(0, "logisLnkEqCd", ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "chassisEqCd"));

            $c.sbm.execute(sbm_ChassisNoChangeInfo);
        } else {
            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisNo", "");
            scwin.badChassisNo = true;
        }
    } else {
        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "chassisNo", "");
        scwin.badChassisNo = true;
    }
};

scwin.f_GateoutProcess = async function(p_gubun) {
    let gridChkYn = 0;
    let copinoAutoSndYn = 0;
    scwin.copinoManualSndYn = 0;

    for (let i = 0; i < ds_Grid1.getRowCount(); i++) {
        if (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") gridChkYn++;

        if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") &&
            (ds_Grid1.getCellData(i, "lineCd") == "ANL" || ds_Grid1.getCellData(i, "lineCd") == "APL") &&
            ds_Grid1.getCellData(i, "fullEmptyClsCd") == "E" && ed_wrkPlCd.getValue() == "4C02") {
            scwin.f_retrieveANLBookingDetail(i);
            if (ds_resultsANLBooking.getRowCount() == 0) {
                if (ds_Grid1.getCellData(i, "lineCd") == "APL") {
                    alert("반출불가\nBOOKING 수신 내역이 없습니다.");
                } else {
                    alert("반출불가\nBOOKING 수신 내역이 없습니다.[ANL반출제어]");
                    return;
                }
            } else {
                let betDt = $c.date.diffDate(ds_resultsANLBooking.getCellData(0, "pickupdt"), ds_Grid1.getCellData(i, "gateoutDth").substr(0, 8));
                if (!(betDt == "0" || betDt == "1" || betDt == "2")) {
                    await $c.gus.cfAlertMsg("해당 BK의 픽업일자는 " +
                        ds_resultsANLBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                        ds_resultsANLBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                        ds_resultsANLBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                        "입니다. \n 반출일시를 확인하시기 바랍니다. 반출일시는 픽업일자 포함 +3일까지 반출이 가능합니다.");
                    return;
                }
            }
        }

        if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ds_Grid1.getCellData(i, "gateoutDth").length != 12) {
            alert((i + 1) + "번째 데이터에서 반출일시를 확인 하십시요.");
            return;
        }
        if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ds_Grid1.getCellData(i, "chkFlag") == "C") {
            alert((i + 1) + "번째 항목은 이미 반출완료된 항목 입니다.");
            return;
        }

        if (p_gubun == "Auto" &&
            (ds_Grid1.getCellData(i, "preInfoSndYn") == "1" || ds_Grid1.getCellData(i, "dptArvPreInfoSndYn") == "1") &&
            (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T")) {
            ds_Grid1.setCellData(i, "copinoAutoSndYn", "1");
            copinoAutoSndYn = 1;
        }

        if (p_gubun == "Manual" &&
            (ds_Grid1.getCellData(i, "preInfoSndYn") == "1" || ds_Grid1.getCellData(i, "dptArvPreInfoSndYn") == "1") &&
            (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T")) {
            scwin.copinoManualSndYn++;
            scwin.copinoRowPosition = i;
        }

        if ((ds_Grid1.getCellData(i, "lineCd") == "ANL" || ds_Grid1.getCellData(i, "lineCd") == "EVER") &&
            (ed_wrkPlCd.getValue() == "4C02" || ed_wrkPlCd.getValue() == "3C01") &&
            (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") &&
            ds_Grid1.getCellData(i, "sealNo") == "") {
            if (ds_Grid1.getCellData(i, "lineCd") == "ANL") {
                alert("의왕CY에서 ANL라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            } else {
                alert("의왕CY에서 EVER라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            }
            return false;
        } else if (ds_Grid1.getCellData(i, "lineCd") == "APL" &&
            ed_wrkPlCd.getValue() == "4C02" &&
            (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") &&
            ds_Grid1.getCellData(i, "sealNo") == "") {
            alert("의왕CY에서 APL라인의 자가 반출인 경우는 SEAL 번호를 입력하셔야 합니다");
            return false;
        }

        if (!$c.gus.cfIsNull(ds_Grid1.getCellData(i, "cxOdrNo"))) {
            if (ds_Grid1.getCellData(i, "cxClntNo") == "999906") {
                alert("미청구된 검색기 오더가 존재합니다. 검색기 오더는 :" + ds_Grid1.getCellData(i, "cxOdrNo") + "청구거래처를 고쳐야 오더등록이 가능합니다.!!!");
                return false;
            } else {
                alert("미청구된 검색기 오더가 존재합니다. 검색기 오더는 :" + ds_Grid1.getCellData(i, "cxOdrNo"));
            }
        }
        if (!$c.gus.cfIsNull(ds_Grid1.getCellData(i, "ciOdrNo"))) {
            if (ds_Grid1.getCellData(i, "ciClntNo") == "999906") {
                alert("미청구된 파출검사 오더가 존재합니다. 파출검사 오더는 :" + ds_Grid1.getCellData(i, "ciOdrNo") + "청구거래처를 고쳐야 오더등록이 가능합니다.!!!");
                return false;
            } else {
                alert("미청구된 파출검사 오더가 존재합니다. 파출검사 오더는 :" + ds_Grid1.getCellData(i, "ciOdrNo"));
            }
        }
    }

    if (p_gubun == "Auto" && copinoAutoSndYn == 0) {
        await $c.gus.cfAlertMsg("COPINO 전송 대상이 없습니다.");
        return;
    }
    if (p_gubun == "Manual") {
        if (gridChkYn > 1) {
            await $c.gus.cfAlertMsg("M/S인 경우 한건만 선택 할 수 있습니다.");
            return;
        }
        if (scwin.copinoManualSndYn == 0) {
            await $c.gus.cfAlertMsg("선택하신 사항중 셔틀 COPINO 전송대상이 포함되어 있지 않습니다.");
            return;
        }
    }

    if (gridChkYn == 0) {
        await $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
        return;
    }

    let curRow = ds_Grid1.getRowPosition();
    if (ds_Grid1.getCellData(curRow, "lineCd") == "WJS" &&
        (ds_Grid1.getCellData(curRow, "selfClsCd") == "JE" || ds_Grid1.getCellData(curRow, "selfClsCd") == "LI")) {
        if (ds_Grid1.getCellData(curRow, "odrKndCd") == "C4" ||
            ds_Grid1.getCellData(curRow, "odrKndCd") == "C6" ||
            (ds_Grid1.getCellData(curRow, "odrKndCd") == "C7" && ds_Grid1.getCellData(curRow, "selfClsCd") == "LI")) {
            if (ds_Grid1.getCellData(curRow, "term") == "" || ds_Grid1.getCellData(curRow, "liVanTerm") == "") {
                alert("TERM 항목이 없습니다.");
                return;
            }
            if (ds_Grid1.getCellData(curRow, "term") != ds_Grid1.getCellData(curRow, "liVanTerm")) {
                alert("TERM 항목이 일치하지 않습니다.");
                return;
            }
        }
    }

    if (!ds_Grid1.isUpdated()) {
        await $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
    } else {
        let confirmResult = await $c.win.confirm("Gate Out 처리 하시겠습니까?");
        if (confirmResult) {
            sbm_GateOut.action = "/ds.op.wrkrslts.cywrkrslts.ProcessGateinCMD.do";
            await $c.sbm.execute(sbm_GateOut);
        }
    }
};

