scwin.f_OzReport = async function() {
    let totRow = ds_Grid1.getRowCount();
    let crryinoutIntendNo = "";

    for (let i = 0; i < totRow; i++) {
        let check = ds_Grid1.getCellData(i, "gridChkBox");
        if (check == "1" || check == "T") {
            crryinoutIntendNo = crryinoutIntendNo + "TO_CHAR(" + ds_Grid1.getCellData(i, "crryinoutIntendNo") + "),";
        }
    }

    crryinoutIntendNo = crryinoutIntendNo.substring(0, crryinoutIntendNo.length - 1);

    if (crryinoutIntendNo.length == 0) {
        await $c.gus.cfAlertMsg("선택된 항목이 없습니다.");
        return;
    }

    // TODO: OZ Report 연동 — cfOZPrint 호출 변환 필요
    let odiParam = { reportId: "op_301_01_05r", crryinoutIntendNo: crryinoutIntendNo };
    $c.gus.cfOZPrint("/ds/op/wrkplan/transwrkplan/op_301_01_05r.ozr", odiParam, null, null);
};

scwin.f_crryInOutEDI = async function(bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag, transWrkIndictNo) {
    if (ds_Grid1.getRowCount() == 0) {
        return;
    }

    if (ds_Grid1.getCellData(row, "chkFlag") != "C" && scwin.copinoManualSndYn == 0) {
        await $c.gus.cfAlertMsg("미처리된 항목입니다. 처리된 항목만 전송 할 수 있습니다.");
        return;
    }

    if (ds_Grid1.getCellData(row, "crryoutEdiType") == "N" && ds_Grid1.getCellData(row, "crryinEdiType") == "N") {
        await $c.gus.cfAlertMsg("EDI전송 대상이 아닙니다");
        return;
    }
    if (ds_Grid1.getCellData(row, "vehclNo") == "") {
        if (bAlertFlag) {
            await $c.gus.cfAlertMsg("운송차량이 없습니다");
        }
        return false;
    }

    let dptWrkPlCd, arvWrkPlCd, dptWrkPlNm, arvWrkPlNm;
    if (ds_Grid1.getCellData(row, "crryinoutClsCd") == "I") {
        dptWrkPlCd = ds_Grid1.getCellData(row, "dptArvWrkPlCd");
        arvWrkPlCd = ds_Grid1.getCellData(row, "wrkPlCd");
        dptWrkPlNm = ds_Grid1.getCellData(row, "wrkPlNm");
        arvWrkPlNm = txt_wrkPlNm.getValue();
    } else if (ds_Grid1.getCellData(row, "crryinoutClsCd") == "O") {
        dptWrkPlCd = ds_Grid1.getCellData(row, "wrkPlCd");
        arvWrkPlCd = ds_Grid1.getCellData(row, "dptArvWrkPlCd");
        dptWrkPlNm = txt_wrkPlNm.getValue();
        arvWrkPlNm = ds_Grid1.getCellData(row, "wrkPlNm");
    }

    if (transWrkIndictNo == "") transWrkIndictNo = ds_Grid1.getCellData(row, "transWrkIndictNo");
    if (transWrkIndictNo == "" || transWrkIndictNo == null) {
        transWrkIndictNo = ds_transWrkIndictNo.getCellData(0, "value");
    }

    let curRow = ds_Grid1.getRowPosition();
    let arrParam = {
        param0: ["1", transWrkIndictNo, ds_Grid1.getCellData(row, "odrNo"), ds_Grid1.getCellData(row, "cntrSeq"),
            ds_Grid1.getCellData(row, "wrkPathSeq"), ds_Grid1.getCellData(row, "wrkStpSeq"),
            ds_Grid1.getCellData(row, "vehclShortNo"), ds_Grid1.getCellData(row, "vehclNo"),
            ds_Grid1.getCellData(row, "vehclIdCardNo"), ds_Grid1.getCellData(row, "wrkStDt"),
            ds_Grid1.getCellData(row, "wrkEndDt"), ds_Grid1.getCellData(row, "cntrNo"),
            dptWrkPlCd, arvWrkPlCd, dptWrkPlNm, arvWrkPlNm,
            ds_Grid1.getCellData(row, "crryoutEdiType"), ds_Grid1.getCellData(row, "crryinEdiType")],
        param1: [transWrkIndictNo, ds_Grid1.getCellData(curRow, "vehclNo"),
            ds_Grid1.getCellData(curRow, "vehclIdCardNo"), ds_Grid1.getCellData(curRow, "drvNm"),
            ds_Grid1.getCellData(curRow, "drvTelNo"),
            ds_Grid1.getCellData(curRow, "gateoutDth").substring(0, 8),
            ds_Grid1.getCellData(curRow, "gateoutDth").substring(8, 12),
            "", "", ds_Grid1.getCellData(curRow, "vehclShortNo"), ds_Grid1.getCellData(curRow, "eqCd")],
        crryoutEdiType: ds_Grid1.getCellData(row, "crryoutEdiType"),
        crryinEdiType: ds_Grid1.getCellData(row, "crryinEdiType"),
        paramTitle: "반출입정보EDI등록"
    };

    let pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_21p.xml";
    await $c.win.openPopup(pURL, { width: 820, height: 730, modal: true, data: arrParam });
    return true;
};

