scwin.f_retrieveBookingDetail = function(Row) {
    if ((ed_wrkPlCd.getValue() == "4C02" || ed_wrkPlCd.getValue() == "3C01" || ed_wrkPlCd.getValue() == "5C07" ||
        ed_wrkPlCd.getValue() == "5C08" || ed_wrkPlCd.getValue() == "7C04") &&
        (ds_Grid1.getCellData(Row, "lineCd") == "EVER" || ds_Grid1.getCellData(Row, "lineCd") == "EMS" ||
            ds_Grid1.getCellData(Row, "lineCd") == "HTML" || ds_Grid1.getCellData(Row, "lineCd") == "EGH" ||
            ds_Grid1.getCellData(Row, "lineCd") == "ITS") &&
        ds_Grid1.getCellData(Row, "fullEmptyClsCd") == "E") {
        dma_searchEverBooking.set("bookingNo", ds_Grid1.getCellData(Row, "bookingNo"));
        dma_searchEverBooking.set("wrkPlCd", ed_wrkPlCd.getValue());
        dma_searchEverBooking.set("cntrSizCd", ds_Grid1.getCellData(Row, "cntrSizCd"));
        dma_searchEverBooking.set("cntrTypCd", ds_Grid1.getCellData(Row, "cntrTypCd"));
        $c.sbm.execute(sbm_retrieveEverBooking);
    }
};

scwin.f_retrieveANLBookingDetail = function(Row) {
    if (ed_wrkPlCd.getValue() == "4C02" &&
        (ds_Grid1.getCellData(Row, "lineCd") == "ANL" || ds_Grid1.getCellData(Row, "lineCd") == "CMA" || ds_Grid1.getCellData(Row, "lineCd") == "APL") &&
        ds_Grid1.getCellData(Row, "fullEmptyClsCd") == "E") {
        dma_searchEverBooking.set("bookingNo", ds_Grid1.getCellData(Row, "bookingNo"));
        dma_searchEverBooking.set("wrkPlCd", ed_wrkPlCd.getValue());
        dma_searchEverBooking.set("cntrSizCd", ds_Grid1.getCellData(Row, "cntrSizCd"));
        dma_searchEverBooking.set("cntrTypCd", ds_Grid1.getCellData(Row, "cntrTypCd"));
        $c.sbm.execute(sbm_retrieveANLBooking);
    }
};

scwin.f_delete = async function() {
    let gridChkYn = 0;
    for (let i = 0; i < ds_Grid1.getRowCount(); i++) {
        if (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") gridChkYn++;
        if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && !(ds_Grid1.getCellData(i, "selfClsCd") == "JE")) {
            alert("자가운송의 경우에만 예정정보 삭제가 가능합니다.");
            return;
        }
    }
    if (gridChkYn == 0) {
        await $c.gus.cfAlertMsg("선택된 사항이 없습니다.");
        return;
    }
    let confirmResult = await $c.win.confirm("삭제된 예정정보는 복구할 수 없습니다. 반출입예정정보를 삭제하시겠습니까?");
    if (confirmResult) {
        await $c.sbm.execute(sbm_Delete);
    }
};

