scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let str = "[[[[" + dataList.getID() + "]]]]]\n";
        for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
            let colCount = dataList.getColumnCount();
            for (let dsCol = 0; dsCol < colCount; dsCol++) {
                let colId = dataList.getColumnID(dsCol);
                str += "[" + colId + "] " + dataList.getCellData(dsRow, colId) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.btn_Save_onclick = function(e) {
    let label = "";
    if (e && e.target) {
        let triggerEl = WebSquare.util.getComponentById(e.target.id);
        if (triggerEl) label = triggerEl.getValue ? triggerEl.getValue() : "";
    }
    if (label == "G/O(A/S)") {
        scwin.f_GateoutProcess("Auto");
    } else if (label == "G/O(M/S)") {
        scwin.f_GateoutProcess("Manual");
    } else if (label == "G/O 처리") {
        scwin.f_GateoutProcess("");
    } else if (label == "예정정보조회") {
        scwin.f_intendPop();
    } else if (label == "경인ICD추적") {
        scwin.f_IcdCar();
    } else if (label == "BK EDI상세내역") {
        scwin.f_BookingDetail();
    } else if (label == "예정정보삭제") {
        scwin.f_delete();
    }
};

