scwin.sbm_retrieveEverBooking_submitdone = async function(e) {
    let rowCnt = ds_resultsEverBooking.getRowCount();
    if (!$c.gus.cfIsNull(ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "masterKey"))) {
        return;
    }
    if (rowCnt == 0) {
        let confirmResult = await $c.win.confirm("BK 수신 내역이 없습니다. \n EVER 선사 담당자에게 문의하세요. \n 그래도 반출 처리하시겠습니까?");
        if (ed_wrkPlCd.getValue() != "4C02") {
            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
            scwin.everBookingCheck = true;
        }
    } else if (rowCnt == 1) {
        if (ds_resultsEverBooking.getCellData(0, "pickupdt") != scwin.sysdate) {
            await $c.gus.cfAlertMsg("해당 BK의 픽업일자는 " +
                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                "입니다. \n 반출 가능한지 선사에 확인바랍니다.");
            if (ed_wrkPlCd.getValue() != "4C02") {
                if (ds_resultsEverBooking.getCellData(0, "pickupdt") > scwin.sysdate) {
                    ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
                    ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
                    scwin.everBookingCheck = true;
                } else {
                    if (scwin.isNotNullGateOutDth) {
                        if (ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "gateoutDth") < ds_resultsEverBooking.getCellData(0, "pickupdt") + ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 4)) {
                            await $c.gus.cfAlertMsg("BK  픽업일시가 반출입일시 보다 빨라야  합니다. \n BK  픽업일시는 " +
                                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                                ds_resultsEverBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                                ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 2) + ":" +
                                ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(10, 2) + " " +
                                "입니다.");
                            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
                            ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
                            scwin.everBookingCheck = true;
                        }
                    }
                }
            } else {
                if (scwin.isNotNullGateOutDth) {
                    if (ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "gateoutDth") < ds_resultsEverBooking.getCellData(0, "pickupdt") + ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 4)) {
                        await $c.gus.cfAlertMsg("BK  픽업일시가 반출입일시 보다 빨라야  합니다. \n BK  픽업일시는 " +
                            ds_resultsEverBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                            ds_resultsEverBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                            ds_resultsEverBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                            ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 2) + ":" +
                            ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(10, 2) + " " +
                            "입니다.");
                    }
                }
            }
            if (!scwin.isNotNullGateOutDth) {
                ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
                ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
                scwin.everBookingCheck = true;
            }
        } else {
            if (scwin.isNotNullGateOutDth) {
                if (ds_Grid1.getCellData(ds_Grid1.getRowPosition(), "gateoutDth") < ds_resultsEverBooking.getCellData(0, "pickupdt") + ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 4)) {
                    await $c.gus.cfAlertMsg("BK  픽업일시가 반출입일시 보다 빨라야  합니다. \n BK  픽업일시는 " +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                        ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 2) + ":" +
                        ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(10, 2) + " " +
                        "입니다.");
                    if (ed_wrkPlCd.getValue() != "4C02") {
                        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
                        ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
                        scwin.everBookingCheck = true;
                    }
                }
            } else {
                if (scwin.sysDtm < ds_resultsEverBooking.getCellData(0, "pickupdt") + ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 4)) {
                    await $c.gus.cfAlertMsg("BK 픽업일시가 저장될 현재일시보다 빨라야합니다. \n BK  픽업일시는 " +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(0, 4) + "/" +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(4, 2) + "/" +
                        ds_resultsEverBooking.getCellData(0, "pickupdt").substr(6, 2) + "  " +
                        ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(8, 2) + ":" +
                        ds_resultsEverBooking.getCellData(0, "rcvDtm").substr(10, 2) + " " +
                        "입니다.");
                    ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gateoutDth", "");
                    ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
                    scwin.everBookingCheck = true;
                }
            }
        }
    } else if (rowCnt > 1) {
        await $c.gus.cfAlertMsg("해당 BK의 수신내역이 여러 건 있으니 반드시 확인후 처리하십시오");
    }
    scwin.isNotNullGateOutDth = false;
};

